// --- CONFIGURATION ---
const config = {
    repulsion: 4000,
    springK: 0.004,      // Spring constant
    damping: 0.92,       // Friction/velocity loss
    gravity: 0.0003,     // Pull towards center
    particleMax: 40,     // Max particles on screen
    particleFade: 0.04,  
    cameraEase: 0.06     // Smoothing factor for camera movement
};

// --- ENTITIES / GRAPH NODES ---
// These are nodes in a physics-based network graph
const nodes = [
    { id: 'mainHub', label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- SPRINGS / EDGES ---
// These connect the nodes together like rubber bands
const springs = [
    { a: 'mainHub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'mainHub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'mainHub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'mainHub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'mainHub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha',   b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma',   b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha',   b: 'epsilon', rest: 200, k: 0.002 }
];

// --- CAMERA ---
const camera = { x: 400, y: 300, zoom: 1 };
const targetCamera = { x: 400, y: 300, zoom: 1 };

// --- PARTICLE SYSTEM ---
const particles = [];
let tick = 0;

// Helper: Find a node by its ID
function getNodeById(id) {
    return nodes.find(node => node.id === id) || null;
}

// --- PHYSICS ENGINE ---
function updatePhysics() {
    // 1. Repulsion force between all nodes (so they don't overlap)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let distance = Math.sqrt(dx * dx + dy * dy) || 1;
            let force = config.repulsion / (distance * distance);

            let fx = (dx / distance) * force;
            let fy = (dy / distance) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring forces (pulling connected nodes together)
    for (let i = 0; i < springs.length; i++) {
        let nodeA = getNodeById(springs[i].a);
        let nodeB = getNodeById(springs[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let distance = Math.sqrt(dx * dx + dy * dy) || 1;
        let extension = distance - springs[i].rest;
        let force = (springs[i].k || config.springK) * extension;

        nodeA.vx += (dx / distance) * force;
        nodeA.vy += (dy / distance) * force;
        nodeB.vx -= (dx / distance) * force;
        nodeB.vy -= (dy / distance) * force;
    }

    // 3. Apply velocity, gravity (pull to center 400, 300), and damping
    for (let i = 0; i < nodes.length; i++) {
        let node = nodes[i];
        node.vx += (400 - node.x) * config.gravity;
        node.vy += (300 - node.y) * config.gravity;

        node.vx *= config.damping;
        node.vy *= config.damping;

        node.x += node.vx;
        node.y += node.vy;
    }
}

// --- PARTICLE SPAWNER ---
function spawnParticle() {
    if (particles.length >= config.particleMax) return;

    // Pick a random node to emit a particle
    let sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * (Math.PI * 2);
    let speed = 0.3 + Math.random() * 0.7;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * 1.2
    });
}

// --- PARTICLE UPDATER ---
function updateParticles() {
    // Loop backwards to safely remove elements while iterating
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];
        p.vx *= 0.995; // Slight friction
        p.vy *= 0.995;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// --- CAMERA UPDATER ---
function updateCamera() {
    // Smoothly interpolate (Lerp) the camera towards the target camera
    camera.x += (targetCamera.x - camera.x) * config.cameraEase;
    camera.y += (targetCamera.y - camera.y) * config.cameraEase;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraEase;
}

// --- MAIN LOOP ---
function mainLoop() {
    updatePhysics();
    updateCamera();

    // Spawn a particle every 3rd tick
    if (tick % 3 === 0) {
        spawnParticle();
    }

    updateParticles();
    tick++;
}

// Run the loop every 16ms (~60 frames per second)
setInterval(mainLoop, 16);
